import { test, expect, Page } from '@playwright/test';

/**
 * ShopFlow AI — Auto-Generated UI Test Suite
 * Generated by : StoryForge AI Framework (Mistral 7B + Jinja2)
 * User Story   : US-001
 * Actor        : registered shopper on ShopFlow
 * Total Cases  : 4 UI tests
 * Tool Stack   : Playwright + TypeScript
 * Target App   : https://shopflow.io
 */

const BASE_URL = 'https://shopflow.io';

// ── Shared helpers ────────────────────────────────────────────
async function login(page: Page) {
  await page.goto(`${BASE_URL}/login`);
  await page.locator('[data-testid="username-input"]').fill('johnsonjoshua');
  await page.locator('[data-testid="password-input"]').fill('Test@3218');
  await page.locator('[data-testid="login-btn"]').click();
  await expect(page).toHaveURL(/home|dashboard/);
}

/**
 * TC-U01 — [Positive]
 * Area     : Search
 * Scenario : Search returns product cards with name, price and image
 * AC       : AC2
 */
test('TC-U01: Search returns product cards with name, price and image', async ({ page }) => {
  // Precondition: authenticated user
  await login(page);

  // Navigate to search
  await page.goto(`${BASE_URL}/search`);
  await page.locator('[data-testid="search-input"]').fill('laptop');
  await page.locator('[data-testid="search-btn"]').click();

  // Assert results contain name, price and image
  const firstResult = page.locator('[data-testid="product-card"]').first();
  await expect(firstResult).toBeVisible();
  await expect(firstResult.locator('[data-testid="product-name"]')).toBeVisible();
  await expect(firstResult.locator('[data-testid="product-price"]')).toBeVisible();
  await expect(firstResult.locator('[data-testid="product-image"]')).toBeVisible();
});

/**
 * TC-U02 — [Negative]
 * Area     : Search
 * Scenario : Invalid search keyword shows no-results message
 * AC       : AC3
 */
test('TC-U02: Invalid search keyword shows no-results message', async ({ page }) => {
  await login(page);

  await page.goto(`${BASE_URL}/search`);
  await page.locator('[data-testid="search-input"]').fill('xyzzy_no_match_999');
  await page.locator('[data-testid="search-btn"]').click();

  // Assert no-results message shown
  await expect(page.locator('[data-testid="no-results-msg"]')).toBeVisible();
  await expect(page.locator('[data-testid="product-card"]')).toHaveCount(0);
});

/**
 * TC-U03 — [Positive]
 * Area     : Cart
 * Scenario : Add to cart updates badge and cart shows correct details
 * AC       : AC4, AC5
 */
test('TC-U03: Add to cart updates badge and cart shows correct details', async ({ page }) => {
  await login(page);

  // Search and add first product to cart
  await page.goto(`${BASE_URL}/search`);
  await page.locator('[data-testid="search-input"]').fill('laptop');
  await page.locator('[data-testid="search-btn"]').click();
  await page.locator('[data-testid="add-to-cart-btn"]').first().click();

  // Assert cart badge updates
  const badge = page.locator('[data-testid="cart-badge"]');
  await expect(badge).toBeVisible();
  const count = await badge.textContent();
  expect(parseInt(count || '0')).toBeGreaterThan(0);

  // Navigate to cart and verify details
  await page.goto(`${BASE_URL}/cart`);
  await expect(page.locator('[data-testid="cart-item-name"]').first()).toBeVisible();
  await expect(page.locator('[data-testid="cart-item-qty"]').first()).toBeVisible();
  await expect(page.locator('[data-testid="cart-total"]')).toBeVisible();
});

/**
 * TC-U04 — [Edge]
 * Area     : Cart
 * Scenario : Empty cart disables checkout button
 * AC       : AC6
 */
test('TC-U04: Empty cart disables checkout button', async ({ page }) => {
  await login(page);

  // Navigate to cart with no items
  await page.goto(`${BASE_URL}/cart`);

  // Assert checkout button is disabled when cart is empty
  const checkoutBtn = page.locator('[data-testid="checkout-btn"]');
  await expect(checkoutBtn).toBeDisabled();
});

